const data = $input.first().json;
const isSuccess = data.status === 'success';
const themeColor = isSuccess ? '00b300' : 'cc0000';
const statusText = isSuccess ? '✅ Passed' : '❌ Failed';
const severity = (data.confidence >= 85) ? 'HIGH' : (data.confidence >= 70) ? 'MEDIUM' : 'LOW';

return [{
  json: {
    '@type': 'MessageCard',
    '@context': 'http://schema.org/extensions',
    themeColor,
    summary: `CI ${data.status}: ${data.pipeline || data.name}`,
    sections: [
      {
        activityTitle: `**${statusText} — ${data.pipeline || data.name || 'Build'}**`,
        activitySubtitle: `Branch: \`${data.branch || 'main'}\` · Repo: ${data.repo || 'unknown'}`,
        activityImage: isSuccess
          ? 'https://img.icons8.com/color/48/ok--v1.png'
          : 'https://img.icons8.com/color/48/cancel--v1.png',
        facts: [
          { name: 'Status', value: data.status },
          { name: 'Branch', value: data.branch || 'main' },
          ...(data.confidence ? [{ name: 'AI Confidence', value: `${data.confidence}% (${severity})` }] : []),
          ...(data.error_summary ? [{ name: 'Root Cause', value: data.error_summary.substring(0, 200) }] : []),
          { name: 'Build #', value: String(data.build_number || data.run_id || 'N/A') },
          { name: 'Commit', value: (data.commit_sha || 'unknown').substring(0, 8) }
        ],
        markdown: true
      }
    ],
    potentialAction: [
      {
        '@type': 'OpenUri',
        name: 'View in Aeon',
        targets: [{ os: 'default', uri: 'http://localhost:3000/ai' }]
      },
      ...(data.url ? [{
        '@type': 'OpenUri',
        name: 'View Build',
        targets: [{ os: 'default', uri: data.url }]
      }] : [])
    ]
  }
}];
